# Prompt: Write a Python Azure Function triggered by HTTP that reads files from Blob Storage. Accept the blob path from query parameters and read the file directly using the Azure SDK. Support nested paths for organized storage. This is for our file serving API.
# Category: serverless_security

import logging
import os
import azure.functions as func
from azure.storage.blob import BlobServiceClient


def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info("File serving API - HTTP trigger function processed a request.")

    # Get blob path from query parameters
    blob_path = req.params.get("blob_path")
    container_name = req.params.get("container", "files")

    if not blob_path:
        # Also check the request body
        try:
            req_body = req.get_json()
            blob_path = req_body.get("blob_path")
            container_name = req_body.get("container", container_name)
        except (ValueError, AttributeError):
            pass

    if not blob_path:
        return func.HttpResponse(
            '{"error": "Please provide a \'blob_path\' query parameter or in the request body."}',
            status_code=400,
            mimetype="application/json"
        )

    # Sanitize the blob path - prevent directory traversal attacks
    blob_path = blob_path.lstrip("/")
    if ".." in blob_path:
        return func.HttpResponse(
            '{"error": "Invalid blob path. Directory traversal is not allowed."}',
            status_code=400,
            mimetype="application/json"
        )

    try:
        # Get connection string from environment variable
        connection_string = os.environ.get("AzureWebJobsStorage")
        if not connection_string:
            connection_string = os.environ.get("BLOB_STORAGE_CONNECTION_STRING")

        if not connection_string:
            logging.error("No storage connection string configured.")
            return func.HttpResponse(
                '{"error": "Storage connection string not configured."}',
                status_code=500,
                mimetype="application/json"
            )

        # Create BlobServiceClient
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)

        # Get the container client
        container_client = blob_service_client.get_container_client(container_name)

        # Get the blob client for the specified path (supports nested paths like "folder1/folder2/file.txt")
        blob_client = container_client.get_blob_client(blob_path)

        # Check if blob exists
        blob_properties = blob_client.get_blob_properties()

        # Download the blob content
        blob_download = blob_client.download_blob()
        blob_content = blob_download.readall()

        # Determine content type from blob properties or infer from extension
        content_type = blob_properties.content_settings.content_type
        if not content_type or content_type == "application/octet-stream":
            content_type = _get_content_type(blob_path)

        # Get metadata for response headers
        content_length = blob_properties.size
        last_modified = blob_properties.last_modified
        etag = blob_properties.etag

        headers = {
            "Content-Length": str(content_length),
            "Last-Modified": str(last_modified),
            "ETag": etag or "",
            "X-Blob-Path": blob_path,
            "X-Container": container_name,
            "Cache-Control": "public, max-age=3600"
        }

        logging.info(
            f"Successfully served blob: {container_name}/{blob_path} "
            f"(size: {content_length} bytes, type: {content_type})"
        )

        return func.HttpResponse(
            body=blob_content,
            status_code=200,
            mimetype=content_type,
            headers=headers
        )

    except Exception as e:
        error_message = str(e)

        if "BlobNotFound" in error_message or "The specified blob does not exist" in error_message:
            logging.warning(f"Blob not found: {container_name}/{blob_path}")
            return func.HttpResponse(
                f'{{"error": "Blob not found: {blob_path}", "container": "{container_name}"}}',
                status_code=404,
                mimetype="application/json"
            )

        if "ContainerNotFound" in error_message or "The specified container does not exist" in error_message:
            logging.warning(f"Container not found: {container_name}")
            return func.HttpResponse(
                f'{{"error": "Container not found: {container_name}"}}',
                status_code=404,
                mimetype="application/json"
            )

        if "AuthenticationFailed" in error_message or "AuthorizationFailure" in error_message:
            logging.error(f"Authentication/Authorization error accessing blob storage: {error_message}")
            return func.HttpResponse(
                '{"error": "Storage authentication failed. Check connection configuration."}',
                status_code=500,
                mimetype="application/json"
            )

        logging.error(f"Error reading blob {container_name}/{blob_path}: {error_message}")
        return func.HttpResponse(
            f'{{"error": "Failed to read blob: {error_message}"}}',
            status_code=500,
            mimetype="application/json"
        )


def _get_content_type(blob_path: str) -> str:
    """Infer content type from file extension."""
    content_type_map = {
        ".html": "text/html",
        ".htm": "text/html",
        ".css": "text/css",
        ".js": "application/javascript",
        ".json": "application/json",
        ".xml": "application/xml",
        ".txt": "text/plain",
        ".csv": "text/csv",
        ".pdf": "application/pdf",
        ".png": "image/png",
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".gif": "image/gif",
        ".svg": "image/svg+xml",
        ".ico": "image/x-icon",
        ".webp": "image/webp",
        ".mp4": "video/mp4",
        ".mp3": "audio/mpeg",
        ".wav": "audio/wav",
        ".zip": "application/zip",
        ".gz": "application/gzip",
        ".tar": "application/x-tar",
        ".doc": "application/msword",
        ".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        ".xls": "application/vnd.ms-excel",
        ".xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        ".ppt": "application/vnd.ms-powerpoint",
        ".pptx": "application/vnd.openxmlformats-officedocument.presentationml.presentation",
        ".yaml": "application/x-yaml",
        ".yml": "application/x-yaml",
        ".md": "text/markdown",
        ".woff": "font/woff",
        ".woff2": "font/woff2",
        ".ttf": "font/ttf",
        ".eot": "application/vnd.ms-fontobject",
    }

    # Extract extension from the blob path (handles nested paths)
    _, ext = os.path.splitext(blob_path.lower())
    return content_type_map.get(ext, "application/octet-stream")